 3984: /*
 3985:  * Read f2fs raw super block.
 3986:  * Because we have two copies of super block, so read both of them
 3987:  * to get the first valid one. If any one of them is broken, we pass
 3988:  * them recovery flag back to the caller.
 3989:  */
 3990: static int read_raw_super_block(struct f2fs_sb_info *sbi,
 3991: 			struct f2fs_super_block **raw_super,
 3992: 			int *valid_super_block, int *recovery)
 3993: {
 3994: 	struct super_block *sb = sbi->sb;
 3995: 	int block;
 3996: 	struct folio *folio;
 3997: 	struct f2fs_super_block *super;
 3998: 	int err = 0;
 3999: 
 4000: 	super = kzalloc(sizeof(struct f2fs_super_block), GFP_KERNEL);
 4001: 	if (!super)
 4002: 		return -ENOMEM;
 4003: 
 4004: 	for (block = 0; block < 2; block++) {
 4005: 		folio = read_mapping_folio(sb->s_bdev->bd_mapping, block, NULL);
 4006: 		if (IS_ERR(folio)) {
 4007: 			f2fs_err(sbi, "Unable to read %dth superblock",
 4008: 				 block + 1);
 4009: 			err = PTR_ERR(folio);
 4010: 			*recovery = 1;
 4011: 			continue;
 4012: 		}
 4013: 
 4014: 		/* sanity checking of raw super */
 4015: 		err = sanity_check_raw_super(sbi, folio, block);
 4016: 		if (err) {
 4017: 			f2fs_err(sbi, "Can't find valid F2FS filesystem in %dth superblock",
 4018: 				 block + 1);
 4019: 			folio_put(folio);
 4020: 			*recovery = 1;
 4021: 			continue;
 4022: 		}
 4023: 
 4024: 		if (!*raw_super) {
 4025: 			memcpy(super, F2FS_SUPER_BLOCK(folio, block),
 4026: 							sizeof(*super));
 4027: 			*valid_super_block = block;
 4028: 			*raw_super = super;
 4029: 		}
 4030: 		folio_put(folio);
 4031: 	}
 4032: 
 4033: 	/* No valid superblock */
 4034: 	if (!*raw_super)
 4035: 		kfree(super);
 4036: 	else
 4037: 		err = 0;
 4038: 
 4039: 	return err;
 4040: }
