 4359: static int f2fs_setup_casefold(struct f2fs_sb_info *sbi)
 4360: {
 4361: #if IS_ENABLED(CONFIG_UNICODE)
 4362: 	if (f2fs_sb_has_casefold(sbi) && !sbi->sb->s_encoding) {
 4363: 		const struct f2fs_sb_encodings *encoding_info;
 4364: 		struct unicode_map *encoding;
 4365: 		__u16 encoding_flags;
 4366: 
 4367: 		encoding_info = f2fs_sb_read_encoding(sbi->raw_super);
 4368: 		if (!encoding_info) {
 4369: 			f2fs_err(sbi,
 4370: 				 "Encoding requested by superblock is unknown");
 4371: 			return -EINVAL;
 4372: 		}
 4373: 
 4374: 		encoding_flags = le16_to_cpu(sbi->raw_super->s_encoding_flags);
 4375: 		encoding = utf8_load(encoding_info->version);
 4376: 		if (IS_ERR(encoding)) {
 4377: 			f2fs_err(sbi,
 4378: 				 "can't mount with superblock charset: %s-%u.%u.%u "
 4379: 				 "not supported by the kernel. flags: 0x%x.",
 4380: 				 encoding_info->name,
 4381: 				 unicode_major(encoding_info->version),
 4382: 				 unicode_minor(encoding_info->version),
 4383: 				 unicode_rev(encoding_info->version),
 4384: 				 encoding_flags);
 4385: 			return PTR_ERR(encoding);
 4386: 		}
 4387: 		f2fs_info(sbi, "Using encoding defined by superblock: "
 4388: 			 "%s-%u.%u.%u with flags 0x%hx", encoding_info->name,
 4389: 			 unicode_major(encoding_info->version),
 4390: 			 unicode_minor(encoding_info->version),
 4391: 			 unicode_rev(encoding_info->version),
 4392: 			 encoding_flags);
 4393: 
 4394: 		sbi->sb->s_encoding = encoding;
 4395: 		sbi->sb->s_encoding_flags = encoding_flags;
 4396: 	}
 4397: #else
 4398: 	if (f2fs_sb_has_casefold(sbi)) {
 4399: 		f2fs_err(sbi, "Filesystem with casefold feature cannot be mounted without CONFIG_UNICODE");
 4400: 		return -EINVAL;
 4401: 	}
 4402: #endif
 4403: 	return 0;
 4404: }
